import { Form, message } from 'antd';
import { getProfileById, setProfileAbout } from 'api/profile';
import noAvatar from 'assets/images/no-avatar.png';
import Loading from 'components/loading';
import CustomModal from 'components/Modal/CustomModal';
import ModalDetail from 'components/Modal/ModalDetail';
import { handleErrorMessage } from 'helper';
import useProfile from 'hooks/useProfile';
import React, { useState } from 'react';
import { useQuery } from 'react-query';
import { useParams } from 'react-router-dom';
import AboutMe from './components/AboutMe';
import Detail from './components/Detail';
import styles from './style.module.scss';

interface ParamTypes {
  id: string;
}

function Profile() {
  const [isOpenModal, setIsOpenModal] = useState({
    about: false,
    detail: false,
  });
  const [form] = Form.useForm();
  const { profile } = useProfile();
  const { id } = useParams<ParamTypes>();
  const { data: profileById, refetch } = useQuery(['fetchProfileById', id], () => getProfileById(Number(id)), {
    enabled: true,
  });
  const [aboutMe, setAboutMe] = useState({ id: Number(id), about: profileById?.about });
  const [detail, setDetail] = useState({
    id: id,
    username: profileById?.username,
    email: profileById?.email,
    address: profileById?.address,
    avatar: profileById?.avatar,
  });

  const handleOkConfirmAbout = async () => {
    try {
      await setProfileAbout(aboutMe);
      await refetch();
      setAboutMe({ ...aboutMe, about: '' });
      setIsOpenModal({ ...isOpenModal, about: false });
      message.success('thay đổi tiêu đề thành công');
      message.destroy();
    } catch (error) {
      handleErrorMessage(error);
    }
  };
  const handleOkConfirm = async () => {
    form.submit();
    await refetch();
    setIsOpenModal({ ...isOpenModal, detail: false });
    setDetail({ ...detail, username: '', email: '', address: '', avatar: '' });
  };

  const changeAbout = (value: string) => {
    setAboutMe({ ...aboutMe, about: value });
  };

  const handleCancelDetail = async () => {
    setIsOpenModal({ ...isOpenModal, detail: false });
    await refetch();
  };

  const handleCancelAbout = () => {
    setAboutMe({ ...aboutMe, about: profileById?.about });
    setIsOpenModal({ ...isOpenModal, about: false });
  };

  return (
    <div className={styles.container}>
      {!profileById && <Loading />}
      <div className={styles.background}></div>
      <div className={styles.profileContainer}>
        <div className={styles.profile}>
          <div className={styles.profileTitle}>
            <h2>Thông tin tài khoản</h2>
          </div>
          <div className={styles.profileContent}>
            <div className={styles.description}>
              <h3 className={styles.about}>đôi lời giới thiệu</h3>
              <p className={styles.aboutContent}>{profileById?.about}</p>
              {profile?.id === Number(id) && (
                <p className={styles.update} onClick={() => setIsOpenModal({ ...isOpenModal, about: true })}>
                  thay đổi
                </p>
              )}
            </div>
            <div className={styles.avatar}>
              <div className={styles.img}>
                <img src={profileById?.avatar ? profileById?.avatar : noAvatar} alt="" />
              </div>
            </div>
            <div className={styles.content}>
              <h3 className={styles.details}>thông tin cá nhân</h3>
              <div className={styles.wrapperName}>
                <p className={styles.name}>Tên: </p>
                <p>{profileById?.username}</p>
              </div>
              <div className={styles.wrapperAge}>
                <p className={styles.age}>Email: </p>
                {profile?.id === Number(id) ? <p>{profileById?.email}</p> : <p>******</p>}
              </div>
              <div className={styles.wrapperAddress}>
                <p className={styles.address}>địa chỉ: </p>
                <p>{profileById?.address}</p>
              </div>
              {profile?.id === Number(id) && (
                <p className={styles.update} onClick={() => setIsOpenModal({ ...isOpenModal, detail: true })}>
                  thay đổi
                </p>
              )}
            </div>
          </div>
        </div>
      </div>

      <CustomModal
        isOpen={isOpenModal.about}
        handleOk={handleOkConfirmAbout}
        handleCancel={handleCancelAbout}
        children={<AboutMe aboutMe={profileById?.about} changeAbout={changeAbout} />}
        title={'About me'}
      />

      <ModalDetail
        isOpen={isOpenModal.detail}
        handleOk={handleOkConfirm}
        handleCancel={handleCancelDetail}
        children={
          <Detail form={form} detail={profile} profile={profileById} refetchProfileById={async () => await refetch()} />
        }
        title={''}
      />
    </div>
  );
}

export default Profile;
